func TestRoundTimeframe() {
	exchange := ccxt.NewExchange().(*ccxt.Exchange)
	exchange.DerivedExchange = exchange
	exchange.InitParent(map[string]interface{}{
		"id": "sampleexchange",
	}, map[string]interface{}{}, exchange)
	var testDate interface{} = exchange.Parse8601("2019-08-12 13:22:08")
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("5m", testDate, ccxt.ROUND_DOWN), exchange.Parse8601("2019-08-12 13:20:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("10m", testDate, ccxt.ROUND_DOWN), exchange.Parse8601("2019-08-12 13:20:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("30m", testDate, ccxt.ROUND_DOWN), exchange.Parse8601("2019-08-12 13:00:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("1d", testDate, ccxt.ROUND_DOWN), exchange.Parse8601("2019-08-12 00:00:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("5m", testDate, ccxt.ROUND_UP), exchange.Parse8601("2019-08-12 13:25:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("10m", testDate, ccxt.ROUND_UP), exchange.Parse8601("2019-08-12 13:30:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("30m", testDate, ccxt.ROUND_UP), exchange.Parse8601("2019-08-12 13:30:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("1h", testDate, ccxt.ROUND_UP), exchange.Parse8601("2019-08-12 14:00:00")))
	Assert(ccxt.IsEqual(exchange.RoundTimeframe("1d", testDate, ccxt.ROUND_UP), exchange.Parse8601("2019-08-13 00:00:00")))
}
